const baseConfig = $('Config Reporte').first().json;
const triggerConfig = $('SetTrigger - Flujo').first()?.json || {};
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();
const timezone = String(config.timezone || 'America/Santiago').trim();
const reportMode = String(config.report_mode || '').trim();
const warrantyDays = Number(config.warranty_warning_days || 90);
const now = new Date();

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}

function scalarText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = String(value).trim();
    return text === '[object Object]' ? '' : text;
  }
  return '';
}

function cleanContactText(value) {
  let text = scalarText(value);
  if (!text) return '';
  if (text.includes(' / ')) text = text.split(' / ')[0].trim();
  return text;
}

function normalizeContactEntry(entry) {
  if (entry === undefined || entry === null) return '';
  const direct = cleanContactText(entry);
  if (direct) return direct;
  if (Array.isArray(entry)) return entry.map(normalizeContactEntry).filter(Boolean).join(', ');
  if (typeof entry === 'object') {
    if (entry.fields && typeof entry.fields === 'object') {
      const fromFields = normalizeContactEntry(entry.fields);
      if (fromFields) return fromFields;
    }
    if (entry.objects && typeof entry.objects === 'object') {
      return Object.values(entry.objects).map(normalizeContactEntry).filter(Boolean).join(', ');
    }
    const preferred = ['contact_id_friendlyname','person_id_friendlyname','user_id_friendlyname','contact_name','person_name','display_name','name','friendlyname','email','email_address'];
    for (const field of preferred) {
      const text = cleanContactText(entry[field]);
      if (text) return text;
    }
    const nested = ['contact_id','person_id','user_id','contact','person','user'];
    for (const field of nested) {
      const text = normalizeContactEntry(entry[field]);
      if (text) return text;
    }
  }
  return '';
}

function normalizeContacts(value) {
  const text = normalizeContactEntry(value);
  if (!text) return '';
  const unique = [];
  const seen = new Set();
  for (const part of text.split(',').map(v => cleanContactText(v)).filter(Boolean)) {
    const key = part.toLowerCase();
    if (!seen.has(key)) { seen.add(key); unique.push(part); }
  }
  return unique.join(', ');
}

function isBlankValue(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'n/a' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined';
}

function normalizeClass(value) {
  const raw = String(value || '-').trim();
  const lower = raw.toLowerCase();
  if (lower === 'pc' || lower.includes('desktop')) return 'PC';
  if (lower === 'laptop' || lower.includes('notebook') || lower.includes('portable')) return 'Laptop';
  if (lower === 'mobilephone' || lower.includes('phone') || lower.includes('telefono') || lower.includes('teléfono')) return 'Teléfonos móviles';
  if (lower === 'tablet') return 'Tablets';
  if (lower === 'printer' || lower.includes('impresora')) return 'Impresoras';
  if (lower === 'peripheral' || lower.includes('periferico') || lower.includes('periférico')) return 'Periféricos';
  if (lower === 'networkdevice') return 'Dispositivos de red';
  return raw || 'Otros';
}

function classSortWeight(className) {
  const order = { 'PC': 10, 'Laptop': 20, 'Tablets': 30, 'Teléfonos móviles': 40, 'Impresoras': 50, 'Periféricos': 60, 'Dispositivos de red': 70, 'Otros': 90 };
  return order[className] || 80;
}

function translateStatus(value) {
  const status = String(value || '').trim().toLowerCase();
  const map = { stock: 'En Inventario', implementation: 'No Productivo', production: 'Productivo', obsolete: 'Obsoleto', inactive: 'Inactivo' };
  return map[status] || String(value || '-');
}

function parseDate(value) {
  const raw = String(value || '').trim();
  if (!raw || raw === '-' || raw.toLowerCase() === 'null') return null;
  const normalized = raw.length === 10 ? `${raw}T00:00:00` : raw.replace(' ', 'T');
  const d = new Date(normalized);
  return Number.isNaN(d.getTime()) ? null : d;
}

function formatDate(value) {
  const d = value instanceof Date ? value : parseDate(value);
  if (!d) return '-';
  return d.toLocaleDateString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' });
}

function daysBetween(a, b) {
  const start = new Date(a.getFullYear(), a.getMonth(), a.getDate());
  const end = new Date(b.getFullYear(), b.getMonth(), b.getDate());
  return Math.ceil((end.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
}

function groupBy(list, fn) {
  const map = new Map();
  for (const item of list) {
    const key = fn(item) || '-';
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(item);
  }
  return map;
}

function buildAssetRows(list, emptyText) {
  if (!list.length) {
    return `<tr><td colspan="9" style="padding:14px; font-size:12px; color:#64748b;">${escapeHtml(emptyText)}</td></tr>`;
  }
  return list.map(a => `
    <tr>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.finalclass)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;"><strong>${escapeHtml(a.name)}</strong></td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.status)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.location)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.brand)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.model)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.serial)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.warrantyDateDisplay)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.daysLabel)}</td>
    </tr>`).join('');
}

function buildClassSummary(list) {
  const groups = [...groupBy(list, a => a.finalclass).entries()]
    .sort((a, b) => classSortWeight(a[0]) - classSortWeight(b[0]) || a[0].localeCompare(b[0], 'es'));
  if (!groups.length) return '<tr><td colspan="2" style="padding:12px; font-size:12px; color:#64748b;">Sin registros para el criterio.</td></tr>';
  return groups.map(([klass, rows]) => `<tr><td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(klass)}</td><td align="right" style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;"><strong>${rows.length}</strong></td></tr>`).join('');
}

const rawRows = flattenInput($input.all());
let assets = rawRows.map(row => {
  const f = row.fields || row;
  const warrantyDate = parseDate(getField(f, ['end_of_warranty', 'warranty_end_date'], ''));
  const contacts = normalizeContacts(getField(f, ['contacts_list', 'contact_list', 'contact_id_friendlyname', 'contact_name'], ''));
  const statusRaw = String(getField(f, ['status'], '-')).trim().toLowerCase();
  const days = warrantyDate ? daysBetween(now, warrantyDate) : null;
  return {
    id: getField(f, ['id', 'key'], row.key || ''),
    name: getField(f, ['name', 'friendlyname'], '-'),
    finalclass: normalizeClass(getField(f, ['finalclass', 'class'], '-')),
    statusRaw,
    status: translateStatus(statusRaw),
    organization: getField(f, ['org_id_friendlyname', 'org_name', 'organization_name'], '-'),
    location: getField(f, ['location_id_friendlyname', 'location_name', 'location_id'], 'Sin bodega/localidad'),
    contact: contacts,
    brand: getField(f, ['brand_id_friendlyname', 'brand'], '-'),
    model: getField(f, ['model_id_friendlyname', 'model'], '-'),
    serial: getField(f, ['serialnumber', 'serial_number'], '-'),
    assetNumber: getField(f, ['asset_number', 'assetnumber'], '-'),
    purchaseDate: getField(f, ['purchase_date'], '-'),
    warrantyDate,
    warrantyDateDisplay: formatDate(warrantyDate),
    daysToWarranty: days,
    daysLabel: days === null ? '-' : (days >= 0 ? `${days} días` : `${Math.abs(days)} días vencida`),
  };
});

if (reportMode === 'without_contact_production') {
  assets = assets.filter(a => a.statusRaw === 'production' && isBlankValue(a.contact));
  assets.sort((a, b) => a.location.localeCompare(b.location, 'es') || classSortWeight(a.finalclass) - classSortWeight(b.finalclass) || a.name.localeCompare(b.name, 'es'));
} else if (reportMode === 'warranty_upcoming') {
  assets = assets.filter(a => a.statusRaw !== 'obsolete' && a.warrantyDate && a.daysToWarranty >= 0 && a.daysToWarranty <= warrantyDays);
  assets.sort((a, b) => a.daysToWarranty - b.daysToWarranty || a.name.localeCompare(b.name, 'es'));
} else if (reportMode === 'warranty_expired') {
  assets = assets.filter(a => a.statusRaw !== 'obsolete' && a.warrantyDate && a.daysToWarranty < 0);
  assets.sort((a, b) => a.daysToWarranty - b.daysToWarranty || a.name.localeCompare(b.name, 'es'));
}

const generatedAt = now.toLocaleString('es-CL', { timeZone: timezone, year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
const generatedAtFile = now.toISOString().replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);
const subjectBase = String(config.email_subject || 'Reporte CMDB').trim();
const emailSubject = itopOrganization ? `${subjectBase} - ${itopOrganization}` : subjectBase;

const headers = ['Clase','Activo','Estado','Bodega','Marca','Modelo','Serie','Garantía','Plazo'];
const csvContent = '\uFEFF' + [
  headers.map(csvEscape).join(';'),
  ...assets.map(a => [a.finalclass,a.name,a.status,a.location,a.brand,a.model,a.serial,a.warrantyDateDisplay,a.daysLabel].map(csvEscape).join(';'))
].join('\r\n');

const groupedByLocation = [...groupBy(assets, a => a.location).entries()]
  .sort((a, b) => a[0].localeCompare(b[0], 'es'));

let detailBlocks = '';
if (!assets.length) {
  detailBlocks = '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">No se encontraron activos para el criterio del reporte.</td></tr></table>';
} else {
  detailBlocks = groupedByLocation.map(([location, rows]) => `
    <div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">${escapeHtml(location)} <span style="font-weight:normal; color:#64748b;">(${rows.length})</span></div>
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;">
      <thead><tr style="background:#f8fafc;">
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Clase</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Activo</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Estado</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Bodega</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Marca</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Modelo</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Serie</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Garantía</th>
        <th align="left" style="padding:8px; font-size:11px; color:#475569;">Plazo</th>
      </tr></thead>
      <tbody>${buildAssetRows(rows, 'Sin registros.')}</tbody>
    </table>`).join('');
}

const csvBaseName = String(config.csv_basename || 'cmdb_reporte_testing').trim();
const withoutLocationCount = assets.filter(a => isBlankValue(a.location) || a.location === 'Sin bodega/localidad').length;
const expiredWarrantyCount = assets.length;
const classTypeCount = new Set(assets.map(a => a.finalclass).filter(Boolean)).size;
const criticalExpiredCount = assets.filter(a => a.daysToWarranty !== null && a.daysToWarranty <= -365).length;

return [{
  json: {
    flags: config.flags || {},
    include_attachment: config.flags?.include_attachment ?? config.include_attachment,
    include_detail: config.flags?.include_detail ?? config.include_detail,
    include_summary: config.flags?.include_summary ?? config.include_summary,
    include_operational_notes: config.flags?.include_operational_notes ?? config.include_operational_notes,
    include_itop_button_footer: config.flags?.include_itop_button_footer ?? config.include_itop_button_footer,
    email_from: config.email_from,
    email_to: config.email_to,
    email_cc: config.email_cc || '',
    email_bcc: config.email_bcc || '',
    email_subject: emailSubject,
    company,
    Company: company,
    itop_organization: itopOrganization || '-',
    generated_at: generatedAt,
    total_assets: String(assets.length),
    warranty_days: String(warrantyDays),
    without_location_count: String(withoutLocationCount),
    expired_warranty_count: String(expiredWarrantyCount),
    class_type_count: String(classTypeCount),
    critical_expired_count: String(criticalExpiredCount),
    class_summary_rows: buildClassSummary(assets),
    detail_blocks: detailBlocks,
    report_title: config.report_title || subjectBase,
    report_description: config.report_description || '',
    operational_notes: config.operational_notes || '',
    itop_url: config.itop_url || '#',
    csv_filename: `${csvBaseName}_${generatedAtFile}.csv`,
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `${csvBaseName}_${generatedAtFile}.csv`,
    },
  },
}];

const input = $input.first();
const data = input.json || {};

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function notesList(value) {
  const lines = String(value ?? '')
    .split(/\r?\n|\. /)
    .map(v => v.trim().replace(/\.$/, ''))
    .filter(Boolean);

  if (!lines.length) return '';

  return `<ul style="margin:0; padding-left:18px; color:#374151; font-size:13px; line-height:20px;">${
    lines.map(line => `<li>${escapeHtml(line)}.</li>`).join('')
  }</ul>`;
}



function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function flagEnabled(name, fallback = true) {
  const trigger = getNodeJson('SetTrigger - Flujo');
  const mixed = getNodeJson('SetMixed - Configuracion efectiva');
  const value = trigger[name] ?? trigger.flags?.[name] ?? data[name] ?? data.flags?.[name] ?? mixed[name] ?? mixed.flags?.[name];
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function removeOuterRowByMarker(html, marker) {
  let index = html.indexOf(marker);
  if (index === -1) return html;
  const starts = ['\n      <tr><td', '\n                        <tr><td', '\n                        <tr><td align', '\n      <tr><td align'];
  let start = -1;
  for (const token of starts) {
    const candidate = html.lastIndexOf(token, index);
    if (candidate > start) start = candidate;
  }
  if (start === -1) start = html.lastIndexOf('<tr><td', index);
  if (start === -1) return html;
  let end = html.indexOf('\n\n      <tr><td', index);
  const endAlt = html.indexOf('\n\n                        <tr><td', index);
  if (end === -1 || (endAlt !== -1 && endAlt < end)) end = endAlt;
  const footerAlt = html.indexOf('\n      <tr><td style="background-color', index);
  if (end === -1 || (footerAlt !== -1 && footerAlt < end)) end = footerAlt;
  const footerAlt2 = html.indexOf('\n                        <tr><td style="background-color', index);
  if (end === -1 || (footerAlt2 !== -1 && footerAlt2 < end)) end = footerAlt2;
  if (end === -1) {
    const close = html.indexOf('</td></tr>', index);
    if (close === -1) return html;
    end = close + '</td></tr>'.length;
  }
  return html.slice(0, start) + html.slice(end);
}

function removeNextOuterRowAfterMarker(html, marker) {
  const index = html.indexOf(marker);
  if (index === -1) return html;
  const firstEnd = html.indexOf('\n\n      <tr><td', index);
  const firstEndAlt = html.indexOf('\n\n                        <tr><td', index);
  let start = firstEnd;
  if (start === -1 || (firstEndAlt !== -1 && firstEndAlt < start)) start = firstEndAlt;
  if (start === -1) return html;
  let end = html.indexOf('\n\n      <tr><td', start + 1);
  const endAlt = html.indexOf('\n\n                        <tr><td', start + 1);
  if (end === -1 || (endAlt !== -1 && endAlt < end)) end = endAlt;
  if (end === -1) return html;
  return html.slice(0, start) + html.slice(end);
}

function applyVisualFlags(html) {
  if (!flagEnabled('include_summary')) {
    html = removeNextOuterRowAfterMarker(html, 'Resumen ejecutivo');
    html = removeOuterRowByMarker(html, 'Resumen ejecutivo');
  }
  if (!flagEnabled('include_detail')) {
    for (const marker of [
      'Detalle operacional',
      'Tickets abiertos pendientes',
      'Tickets abiertos por agente',
      'Tickets con más de 14 días abiertos',
      'Tickets abiertos hasta 14 días',
      'older_section',
      'recent_section',
      'ticket_sections',
      'data-table',
      'ticket-table'
    ]) {
      let previous;
      do {
        previous = html;
        html = removeOuterRowByMarker(html, marker);
      } while (html !== previous);
    }
  }
  if (!flagEnabled('include_operational_notes')) {
    html = removeOuterRowByMarker(html, 'Observaciones operacionales');
  }
  if (!flagEnabled('include_itop_button_footer')) {
    html = removeOuterRowByMarker(html, 'Abrir Combodo iTop');
  }
  return html;
}

const template = `<!DOCTYPE html>
